package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;

import com.google.gson.stream.JsonReader;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

import java.io.Reader;
import java.io.StringReader;
import java.lang.reflect.Field;

class Gson_newJsonReader_Test {

  private Gson gson;

  @BeforeEach
  public void setUp() {
    gson = new Gson();
  }

  @Test
  public void testNewJsonReader_withLenientTrue() throws Exception {
    // Create Gson instance with lenient = true by reflection setting the private field
    gson = createGsonWithLenient(true);

    String json = "{\"key\":\"value\"}";
    Reader reader = new StringReader(json);

    JsonReader jsonReader = gson.newJsonReader(reader);

    assertNotNull(jsonReader);

    // Use reflection to get the 'in' field from JsonReader (the Reader passed in constructor)
    Field inField = JsonReader.class.getDeclaredField("in");
    inField.setAccessible(true);
    Object actualReader = inField.get(jsonReader);

    assertSame(reader, actualReader);
    // lenient should be true as set by Gson.lenient and applied by newJsonReader()
    assertTrue(jsonReader.isLenient());
  }

  @Test
  public void testNewJsonReader_withLenientFalse() throws Exception {
    // Create Gson instance with lenient = false by reflection setting the private field
    gson = createGsonWithLenient(false);

    String json = "{\"key\":\"value\"}";
    Reader reader = new StringReader(json);

    JsonReader jsonReader = gson.newJsonReader(reader);

    assertNotNull(jsonReader);

    // Use reflection to get the 'in' field from JsonReader (the Reader passed in constructor)
    Field inField = JsonReader.class.getDeclaredField("in");
    inField.setAccessible(true);
    Object actualReader = inField.get(jsonReader);

    assertSame(reader, actualReader);
    // lenient should be false as set by Gson.lenient and applied by newJsonReader()
    assertFalse(jsonReader.isLenient());
  }

  @Test
  public void testNewJsonReader_withNullReader() {
    assertThrows(NullPointerException.class, () -> {
      gson.newJsonReader(null);
    });
  }

  private Gson createGsonWithLenient(boolean lenientValue) throws Exception {
    // Create a default Gson instance and set its private final 'lenient' field by reflection
    Gson gsonInstance = new Gson();

    Field lenientField = Gson.class.getDeclaredField("lenient");
    lenientField.setAccessible(true);

    // Remove final modifier if present (for Java 12+ compatibility)
    Field modifiersField = Field.class.getDeclaredField("modifiers");
    modifiersField.setAccessible(true);
    modifiersField.setInt(lenientField, lenientField.getModifiers() & ~java.lang.reflect.Modifier.FINAL);

    lenientField.set(gsonInstance, lenientValue);

    return gsonInstance;
  }
}
